mapper.select:
select CONCAT(CONVERT(varchar(10), a.tran_date, 23), ' - ', a.seq) AS tranDateSeq ,b.storage_name ,c.client_name , min(a.item_name)+ case when count(distinct a.item_cd) > 1 then ' 외 ' + cast(count(distinct a.item_cd) - 1 as varchar(10)) + '건' else '' end as item_name , sum(a.qty) as qty ,d.member_nm ,a.tran_id from vw_inv_stock_tran a left outer join tb_storage_mst b on b.storage_cd = a.storage_cd left outer join tb_client_mst c on c.client_id = a.customer_cd left outer join tb_users d on d.user_id = a.manager_id where a.tran_date between #{strDate} and #{endDate} and a.tran_type_cd ='F'
and a.area_cd = #{areaCd}
and a.storage_cd = #{srcStorageCd}
and b.item_cd like '%' + #{itemCd} + '%'
and b.item_name like '%' + #{itemName} + '%'
group by a.tran_date, a.seq , b.storage_name,c.client_name , a.item_name, a.item_cd,d.member_nm, a.tran_id order by a.tran_date desc, a.seq desc

mapper.update:
update tb_inv_tran_item
set    qty = #{qty}
      ,upd_id = #{userId}
      ,upd_dt = getdate()
where  tran_id = #(tranId)
